import { useState, useCallback, useEffect } from 'react';
import { optimise } from './engineV2';
import { I18N } from './i18n';
import { supabase, saveProject, loadProject, signOut } from './supabase';
import ProjectForm from './components/ProjectForm';
import PiecesList from './components/PiecesList';
import Results from './components/Results';
import AuthScreen from './components/AuthScreen';
import ProjectsScreen from './components/ProjectsScreen';
import Header from './components/Header';
import './App.css';

const SCREENS = { AUTH: 'auth', PROJECTS: 'projects', FORM: 'form', PIECES: 'pieces', RESULTS: 'results' };
const DEFAULT_PROJECT = { name: '', client: '', company: '', panel: { w: 244, h: 122 }, kerf: 3, tolerance: 10, pricePerPanel: 39.8, pieces: [], furniture: [], devisNum: '', supabaseId: null };

export default function App() {
  const [langOverride, setLangOverride] = useState('fr');
  // On s'assure que tr est bien recalculé à chaque render
  const tr = I18N[langOverride] || I18N['fr']; 

  const [screen, setScreen] = useState(SCREENS.AUTH);
  const [user, setUser] = useState(null);
  const [project, setProject] = useState({ ...DEFAULT_PROJECT });
  const [results, setResults] = useState(null);
  const [computing, setComputing] = useState(false);
  const [saving, setSaving] = useState(false);
  const [saveMsg, setSaveMsg] = useState('');

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) { setUser(session.user); setScreen(SCREENS.PROJECTS); }
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) { setUser(session.user); setScreen(SCREENS.PROJECTS); }
      else { setUser(null); setScreen(SCREENS.AUTH); }
    });
    return () => subscription.unsubscribe();
  }, []);

  const startNew = (devisNum = '') => { setProject({ ...DEFAULT_PROJECT, devisNum }); setResults(null); setScreen(SCREENS.FORM); };

  const goBack = () => {
    if (screen === SCREENS.RESULTS) setScreen(SCREENS.PIECES);
    else if (screen === SCREENS.PIECES) setScreen(SCREENS.FORM);
    else if (screen === SCREENS.FORM) setScreen(user ? SCREENS.PROJECTS : SCREENS.AUTH);
    else setScreen(SCREENS.AUTH);
  };

  const handleLoadProject = async (id) => {
    const { data, error } = await loadProject(id);
    if (error || !data) return;
    const p = { ...data.project_data, supabaseId: data.id };
    setProject(p);
    if (data.results_data) { setResults(data.results_data); setScreen(SCREENS.RESULTS); }
    else setScreen(SCREENS.PIECES);
  };

  const handleOptimize = useCallback(() => {
    if (!project.pieces.length) return;
    setComputing(true);
    setTimeout(async () => {
      const res = optimise(project.pieces, project.panel, { kerf: project.kerf, tolerance: project.tolerance });
      setResults(res); setComputing(false); setScreen(SCREENS.RESULTS);
      if (user) {
        setSaving(true);
        const { data, error } = await saveProject(project, res);
        setSaving(false);
        if (!error && data) { setProject(p => ({ ...p, supabaseId: data.id })); setSaveMsg('✓ Sauvegardé'); setTimeout(() => setSaveMsg(''), 3000); }
      }
    }, 50);
  }, [project, user]);

  const handleSave = async () => {
    if (!user) { alert("Connectez-vous pour sauvegarder"); return; }
    setSaving(true);
    const { data, error } = await saveProject(project, results);
    setSaving(false);
    if (!error && data) { 
      setProject(p => ({ ...p, supabaseId: data.id })); 
      setSaveMsg('✓ Sauvegardé'); 
    } else { 
      setSaveMsg('✗ Erreur'); 
    }
    setTimeout(() => setSaveMsg(''), 3000);
  };

  const handleSignOut = async () => { await signOut(); setUser(null); setScreen(SCREENS.AUTH); };

  const toggleLang = () => {
    const newLang = langOverride === 'fr' ? 'en' : 'fr';
    console.log("Switching language to:", newLang);
    setLangOverride(newLang);
  };

  const devisNum = 'DV-' + new Date().getFullYear() + '-' + String(Math.floor(Math.random() * 9000) + 1000);
  const showBack = [SCREENS.FORM, SCREENS.PIECES, SCREENS.RESULTS].includes(screen);
  const showSave = user && [SCREENS.PIECES, SCREENS.RESULTS].includes(screen);

  let headerTitle = "PanelCut Pro"; let headerSubtitle = ""; let steps = [];

  if (screen === SCREENS.PROJECTS) { headerTitle = tr.appName || "Dashboard"; headerSubtitle = user?.email || "Guest"; }
  else if (screen === SCREENS.FORM) { headerTitle = tr.newProject; headerSubtitle = tr.configuration; steps = [{ label: tr.panel, active: true }, { label: tr.pieces, active: false }, { label: tr.results, active: false }]; }
  else if (screen === SCREENS.PIECES) { headerTitle = project.name || tr.newProject; headerSubtitle = tr.piecesToCut; steps = [{ label: tr.panel, active: true }, { label: tr.pieces, active: true }, { label: tr.results, active: false }]; }
  else if (screen === SCREENS.RESULTS) { headerTitle = tr.results; headerSubtitle = tr.optimizedLayout; steps = [{ label: tr.panel, active: true }, { label: tr.pieces, active: true }, { label: tr.results, active: true }]; }

  const hasHeader = screen !== SCREENS.AUTH;

  return (
    <div className="app min-h-screen bg-[#050505] text-slate-200 font-sans selection:bg-orange-500 selection:text-white">
      {hasHeader && (
        <Header 
          title={headerTitle} 
          subtitle={headerSubtitle} 
          onBack={showBack ? goBack : undefined}
          user={user} 
          onLogout={handleSignOut} 
          steps={steps}
          onSave={showSave ? handleSave : undefined} 
          saving={saving} 
          saveMsg={saveMsg}
          lang={langOverride} 
          onToggleLang={toggleLang}
        />
      )}

              <main className={`w-full max-w-5xl mx-auto px-4 ${hasHeader ? 'mt-24 mb-20' : 'mt-0'}`}>
        {/* On ajoute key={langOverride} SUR CHAQUE composant pour forcer leur recréation totale */}
        {screen === SCREENS.AUTH && <AuthScreen key={langOverride} onSkip={() => setScreen(SCREENS.PROJECTS)} />}

        {screen === SCREENS.PROJECTS && (
          <ProjectsScreen key={langOverride} user={user} onNew={() => startNew(devisNum)} onLoad={handleLoadProject} />
        )}

        {screen === SCREENS.FORM && (
          <ProjectForm key={langOverride} t={tr} project={project} onChange={setProject} onNext={() => setScreen(SCREENS.PIECES)} />
        )}

        {screen === SCREENS.PIECES && (
          <PiecesList key={langOverride} t={tr} project={project} onChange={setProject} onOptimize={handleOptimize} computing={computing} />
        )}

        {screen === SCREENS.RESULTS && results && (
          <Results key={langOverride} t={tr} results={results} project={project} />
        )}
      </main>
    </div>
  );
}
